package com.restaurantcraft.command;
import com.mojang.brigadier.CommandDispatcher; import com.mojang.brigadier.arguments.IntegerArgumentType; import com.restaurantcraft.blockentity.RestaurantManagementBlockEntity; import net.minecraft.commands.*; import net.minecraft.core.BlockPos; import net.minecraft.network.chat.Component; import net.minecraft.server.level.ServerPlayer;
public class RestaurantCommand { public static void register(CommandDispatcher<CommandSourceStack> d){ d.register(Commands.literal("restaurantcraft").requires(s->s.hasPermission(2)).then(Commands.literal("info").executes(c->info(c.getSource()))).then(Commands.literal("close").executes(c->close(c.getSource()))).then(Commands.literal("addpopularity").then(Commands.argument("amount",IntegerArgumentType.integer()).executes(c->addPop(c.getSource(),IntegerArgumentType.getInteger(c,"amount"))))).then(Commands.literal("addmoney").then(Commands.argument("amount",IntegerArgumentType.integer()).executes(c->addMoney(c.getSource(),IntegerArgumentType.getInteger(c,"amount"))))).then(Commands.literal("reset").executes(c->reset(c.getSource()))).then(Commands.literal("debug").then(Commands.literal("area").executes(c->area(c.getSource()))))); }
 static RestaurantManagementBlockEntity find(CommandSourceStack s){ if(!(s.getEntity() instanceof ServerPlayer p))return null; BlockPos pp=p.blockPosition(); for(BlockPos b:BlockPos.betweenClosed(pp.offset(-32,-8,-32),pp.offset(32,8,32))) if(p.level().getBlockEntity(b) instanceof RestaurantManagementBlockEntity be) return be; return null; }
 static int info(CommandSourceStack s){var be=find(s); if(be==null){s.sendFailure(Component.literal("No restaurant nearby"));return 0;} s.sendSuccess(()->Component.literal(be.data.restaurantName+" 星级:"+be.data.level+" 人气:"+be.data.popularity+" 额度:"+be.data.money+" 营业:"+be.data.isOpen),false);return 1;} static int close(CommandSourceStack s){var be=find(s); if(be!=null)be.endBusiness(true);return 1;} static int addPop(CommandSourceStack s,int a){var be=find(s); if(be!=null){be.data.popularity=Math.max(0,be.data.popularity+a);be.setChanged();}return 1;} static int addMoney(CommandSourceStack s,int a){var be=find(s); if(be!=null){be.data.money+=a;be.setChanged();}return 1;} static int reset(CommandSourceStack s){var be=find(s); if(be!=null)be.reset();return 1;} static int area(CommandSourceStack s){var be=find(s); if(be!=null){be.detectArea();s.sendSuccess(()->Component.literal("min="+be.data.areaMinPos+" max="+be.data.areaMaxPos+" entrance="+be.data.entrancePos+" exit="+be.data.exitPos),false);} return 1;} }